import React, { useState, useEffect } from 'react';
import { View, Text, Button, StyleSheet, Alert, ActivityIndicator } from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';
import * as SecureStore from 'expo-secure-store';
import { makeRedirectUri } from 'expo-auth-session';

WebBrowser.maybeCompleteAuthSession();

const OAUTH_CONFIG = {
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  tokenEndpoint: 'https://your-auth-server.com/oauth/token',
  revocationEndpoint: 'https://your-auth-server.com/oauth/revoke',
  clientId: 'mobile_app_client_123',
  scopes: ['read', 'write', 'profile'],
};

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userInfo, setUserInfo] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  const redirectUri = makeRedirectUri({
    scheme: 'myapp',
    path: 'redirect'
  });

  const discovery = {
    authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
    tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
    revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
  };

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH_CONFIG.clientId,
      scopes: OAUTH_CONFIG.scopes,
      redirectUri: redirectUri,
      usePKCE: true,
      responseType: AuthSession.ResponseType.Code,
    },
    discovery
  );

  useEffect(() => {
    checkExistingAuth();
  }, []);

  useEffect(() => {
    if (response?.type === 'success') {
      const { code } = response.params;
      exchangeCodeForToken(code);
    } else if (response?.type === 'error') {
      Alert.alert('Authentication Error', response.error?.message || 'Failed to authenticate');
    }
  }, [response]);

  const checkExistingAuth = async () => {
    try {
      const accessToken = await SecureStore.getItemAsync('access_token');
      const refreshToken = await SecureStore.getItemAsync('refresh_token');
      
      if (accessToken) {
        const isValid = await validateToken(accessToken);
        if (isValid) {
          setIsAuthenticated(true);
          await fetchUserInfo(accessToken);
        } else if (refreshToken) {
          await refreshAccessToken(refreshToken);
        }
      }
    } catch (error) {
      console.error('Error checking auth:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      setIsLoading(true);
      
      const tokenResponse = await AuthSession.exchangeCodeAsync(
        {
          clientId: OAUTH_CONFIG.clientId,
          code: code,
          redirectUri: redirectUri,
          extraParams: {
            code_verifier: request?.codeVerifier,
          },
        },
        discovery
      );

      await SecureStore.setItemAsync('access_token', tokenResponse.accessToken);
      
      if (tokenResponse.refreshToken) {
        await SecureStore.setItemAsync('refresh_token', tokenResponse.refreshToken);
      }

      setIsAuthenticated(true);
      await fetchUserInfo(tokenResponse.accessToken);
    } catch (error) {
      console.error('Token exchange error:', error);
      Alert.alert('Error', 'Failed to complete authentication');
    } finally {
      setIsLoading(false);
    }
  };

  const validateToken = async (token) => {
    try {
      const response = await fetch('https://your-auth-server.com/oauth/validate', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
      });
      return response.ok;
    } catch (error) {
      return false;
    }
  };

  const refreshAccessToken = async (refreshToken) => {
    try {
      const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          refresh_token: refreshToken,
          client_id: OAUTH_CONFIG.clientId,
        }).toString(),
      });

      if (response.ok) {
        const data = await response.json();
        await SecureStore.setItemAsync('access_token', data.access_token);
        
        if (data.refresh_token) {
          await SecureStore.setItemAsync('refresh_token', data.refresh_token);
        }

        setIsAuthenticated(true);
        await fetchUserInfo(data.access_token);
        return true;
      } else {
        await logout();
        return false;
      }
    } catch (error) {
      console.error('Token refresh error:', error);
      await logout();
      return false;
    }
  };

  const fetchUserInfo = async (token) => {
    try {
      const response = await fetch('https://your-auth-server.com/api/user', {
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });

      if (response.ok) {
        const data = await response.json();
        setUserInfo(data);
      }
    } catch (error) {
      console.error('Error fetching user info:', error);
    }
  };

  const handleLogin = async () => {
    try {
      await promptAsync();
    } catch (error) {
      Alert.alert('Error', 'Failed to initiate login');
    }
  };

  const logout = async () => {
    try {
      const accessToken = await SecureStore.getItemAsync('access_token');
      
      if (accessToken) {
        await AuthSession.revokeAsync(
          {
            clientId: OAUTH_CONFIG.clientId,
            token: accessToken,
          },
          discovery
        );
      }

      await SecureStore.deleteItemAsync('access_token');
      await SecureStore.deleteItemAsync('refresh_token');
      
      setIsAuthenticated(false);
      setUserInfo(null);
    } catch (error) {
      console.error('Logout error:', error);
    }
  };

  if (isLoading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      {!isAuthenticated ? (
        <View style={styles.loginContainer}>
          <Text style={styles.title}>Welcome to MyApp</Text>
          <Button
            title="Login with OAuth"
            onPress={handleLogin}
            disabled={!request}
          />
        </View>
      ) : (
        <View style={styles.profileContainer}>
          <Text style={styles.title}>Welcome!</Text>
          {userInfo && (
            <View style={styles.userInfo}>
              <Text style={styles.label}>User ID: {userInfo.id}</Text>
              <Text style={styles.label}>Email: {userInfo.email}</Text>
              <Text style={styles.label}>Name: {userInfo.name}</Text>
            </View>
          )}
          <Button title="Logout" onPress={logout} color="#ff0000" />
        </View>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: '#f5f5f5',
    padding: 20,
  },
  loginContainer: {
    alignItems: 'center',
  },
  profileContainer: {
    alignItems: 'center',
    width: '100%',
  },
  title: {
    fontSize: 24,
    fontWeight: 'bold',
    marginBottom: 30,
  },
  userInfo: {
    backgroundColor: '#fff',
    padding: 20,
    borderRadius: 10,
    marginBottom: 20,
    width: '100%',
  },
  label: {
    fontSize: 16,
    marginBottom: 10,
  },
});

export default App;